import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { Quote, LineItem } from '../../data/models';

@Component({
  selector: 'app-quote-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './quote-detail.component.html',
  styleUrl: './quote-detail.component.css',
})
export class QuoteDetailComponent {
  readonly id: string | null;
  readonly quote: Quote | undefined;
  readonly lineItems = signal<LineItem[]>([]);
  readonly panelOpen = signal<boolean>(false);

  errorLines = computed(() => this.lineItems().filter((l) => l.validationStatus === 'error'));
  warningLines = computed(() => this.lineItems().filter((l) => l.validationStatus === 'warning'));
  issueLines = computed(() => this.lineItems().filter((l) => l.validationStatus !== 'ok'));

  constructor(
    public seed: SeedService,
    private route: ActivatedRoute,
    private router: Router,
  ) {
    this.id = this.route.snapshot.paramMap.get('id');
    this.quote = this.id ? this.seed.quoteById(this.id) : undefined;
    if (this.id) this.lineItems.set(this.seed.lineItemsForQuote(this.id));
    this.panelOpen.set(this.route.snapshot.queryParamMap.get('panel') === 'validation');
  }

  lineTotal(li: LineItem): number {
    return li.qty * li.unitPrice;
  }

  toggleValidationPanel(): void {
    const next = !this.panelOpen();
    this.panelOpen.set(next);
    this.router.navigate([], {
      queryParams: { panel: next ? 'validation' : null },
      queryParamsHandling: 'merge',
    });
  }

  lineBadge(status: LineItem['validationStatus']): string {
    switch (status) {
      case 'ok': return 'badge-success';
      case 'warning': return 'badge-warning';
      case 'error': return 'badge-danger';
      default: return 'badge-neutral';
    }
  }

  statusBadge(status: Quote['status']): string {
    switch (status) {
      case 'draft': return 'badge-neutral';
      case 'submitted': return 'badge-info';
      case 'won': return 'badge-success';
      case 'lost': return 'badge-danger';
      default: return 'badge-neutral';
    }
  }
}
